def word_frequency(text: str) -> dict[str, int]:
    import re
    from collections import defaultdict

    frequency = defaultdict(int)
    words = re.findall(r'\b\w+\b', text.lower())

    for word in words:
        frequency[word] += 1

    return dict(frequency)
